changeSet.sql:
CREATE TABLE document_access_tokens
(
	id serial,
	code character varying (64) NOT NULL,
	user_id integer NOT NULL,
	document_id integer NOT NULL,
	active boolean NOT NULL DEFAULT true,
	created_at timestamp without time zone NOT NULL DEFAULT now(),
	expired_at timestamp without time zone NOT NULL DEFAULT now(),
	CONSTRAINT pk_document_access_tokens PRIMARY KEY (id)
	, CONSTRAINT fk_document_access_tokens_to_user FOREIGN KEY (user_id) REFERENCES users (id) MATCH SIMPLE ON UPDATE NO ACTION ON DELETE NO ACTION
);
CREATE UNIQUE INDEX ui_document_access_tokens_code ON document_access_tokens (code);
CREATE INDEX i_document_access_tokens_user ON document_access_tokens (user_id);
CREATE INDEX i_document_access_tokens_document ON document_access_tokens (document_id);
CREATE INDEX i_document_access_tokens_expired ON document_access_tokens (expired_at);

-- User Password reset link index
CREATE INDEX i_user_password_reset_links_expired ON user_password_reset_links (expired_at);
